&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;चंद्र प्रभा वन्यजीव अभयारण्य&lt;/span&gt;, जिसे चंद्रप्रभा के नाम से भी जाना जाता है, मध्य भारत में उत्तर प्रदेश राज्य के चंदौली जिले में स्थित है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;चंद्र प्रभा वन्यजीव अभयारण्य ऐतिहासिक शहर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;वाराणसी&lt;/span&gt;&amp;nbsp;से लगभग 70 किलोमीटर दूर स्थित है।&lt;/li&gt;
	&lt;li&gt;वन्यजीव अभयारण्य&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;मई 1957 में स्थापित&lt;/span&gt;&amp;nbsp;किया गया था।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;करमनाशा नदी&lt;/span&gt;, गंगा की एक सहायक नदी, अभयारण्य से होकर बहती है, जैसे कि&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;चंद्रप्रभा नदी, करमनाशा की एक सहायक नदी है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;पशुओं में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;तेंदुआ, जंगली सूअर, नीलगाय, सांभर हिरण, चिंकारा, और चीतल&lt;/span&gt;&amp;nbsp;और पक्षियों की कई प्रजातियां शामिल हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;महानंदा&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;महानंदा वन्यजीव अभयारण्य&lt;/span&gt;&amp;nbsp;हिमालय की तलहटी में,&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;तीस्ता और महानंदा नदियों के बीच&amp;nbsp;&lt;/span&gt;स्थित है।&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;पश्चिम बंगाल, भारत के दार्जिलिंग जिले&lt;/span&gt;&amp;nbsp;में स्थित; यह दार्जिलिंग वन्यजीव प्रभाग के अंतर्गत आता है।&lt;/li&gt;
	&lt;li&gt;यह&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;1955 में एक खेल अभयारण्य के रूप में प्रारंभ&lt;/span&gt;&amp;nbsp;किया गया था।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;1959&lt;/span&gt;&amp;nbsp;में, इसे मुख्य रूप से&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;भारतीय बाइसन और शाही बंगाल बाघ की रक्षा&lt;/span&gt;&amp;nbsp;के लिए&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;एक अभयारण्य का दर्जा मिला&lt;/span&gt;, जो विलुप्त होने के खतरे का सामना कर रहे थे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;लखारी घाटी&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;लखारी घाटी वन्यजीव अभयारण्य&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;गंजम जिला, ओडिशा, भारत&lt;/span&gt;&amp;nbsp;में स्थित है।&lt;/li&gt;
	&lt;li&gt;वन्यजीव अभयारण्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;पूर्वी घाट पर्वतमाला के लखारी घाटी&lt;/span&gt;&amp;nbsp;में है।&lt;/li&gt;
	&lt;li&gt;लखारी घाटी अभयारण्य की&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;स्थापना वर्ष 1985 में&amp;nbsp;&lt;/span&gt;हुई थी।&lt;/li&gt;
	&lt;li&gt;यह स्थान&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;उष्णकटिबंधीय जलवायु&lt;/span&gt;&amp;nbsp;से समृद्ध है और बंगाल की खाड़ी से इसकी निकटता के कारण&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;प्रत्येक वर्ष भारी मात्रा में वर्षा&lt;/span&gt;&amp;nbsp;प्राप्त करता है।&lt;/li&gt;
	&lt;li&gt;अभयारण्य समृद्ध उष्णकटिबंधीय वन, घाटियों, पहाड़ियों, जल स्रोतों आदि से भरा है, जो अभयारण्य में एक आकर्षक माहौल बनाते हैं।&lt;/li&gt;
	&lt;li&gt;लखारी घाटी अभयारण्य&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;बड़ी संख्या में हाथियों&lt;/span&gt;&amp;nbsp;का निवास स्थान है।&lt;/li&gt;
	&lt;li&gt;अभयारण्य भारत में हाथी की जनसंख्या वाले अभयारण्यों में से एक है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पंचमढ़ी&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पंचमढ़ी बायोस्फीयर रिजर्व&amp;nbsp;&lt;/span&gt;मध्य भारत में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;मध्य प्रदेश राज्य की सतपुड़ा पर्वतमाला&amp;nbsp;&lt;/span&gt;में एक गैर-उपयोग संरक्षण क्षेत्र और बायोस्फीयर रिजर्व है।&lt;/li&gt;
	&lt;li&gt;संरक्षण क्षेत्र&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;1999&amp;nbsp;&lt;/span&gt;में सरकार द्वारा&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;बनाया गया&amp;nbsp;&lt;/span&gt;था।&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;यूनेस्को ने 2009 में एक बायोस्फियर रिज़र्व नामित किया था।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;इसमें तीन वन्यजीव संरक्षण इकाइयां शामिल हैं:
	&lt;ul&gt;
		&lt;li&gt;बोरी अभयारण्य&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पंचमढ़ी अभयारण्य&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;सतपुड़ा राष्ट्रीय उद्यान&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;विशाल स्तनधारियों की प्रजातियों में&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;चिंकारा, नीलगाय, जंगली कुत्ते, भारतीय भेड़िया, बाइसन, भारतीय विशाल गिलहरी और उड़ने वाली गिलहरी&lt;/span&gt;&amp;nbsp;शामिल हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #faf4eb;&quot;&gt;The correct answer is&amp;nbsp;&lt;strong&gt;Kumbh Mela&lt;/strong&gt;&lt;/p&gt;

&lt;p data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #faf4eb;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points:&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #faf4eb;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Kumbh Mela&lt;/span&gt;&amp;nbsp;is a major festival and&amp;nbsp;pilgrimage&amp;nbsp;in Hinduism.&lt;/li&gt;
	&lt;li&gt;The festival&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Kumbh&lt;/span&gt;&amp;nbsp;is celebrated in a cycle of approximately&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;12 years at four river-bank pilgrimage sites.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The sites are
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Prayagraj (Ganges-Yamuna Sarasvati rivers confluence)&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Nashik (Godavari)&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Haridwar (Ganges)&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Ujjain (Shipra)&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;Approximately&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;30and 50&amp;nbsp;million people&lt;/span&gt;&amp;nbsp;attended Maha Kumbh Mela in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;2013&amp;nbsp;&lt;/span&gt;and&amp;nbsp;the Allahabad Ardh Kumbh Mela in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;2019.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;On Amavasya&lt;/span&gt;,&amp;nbsp;the most cherished day for bathing the pilgrims welcome and wait for the thirteen sadhu akharas to bathe first.&lt;/li&gt;
	&lt;li&gt;This Programme is called&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;shahi snan&lt;/span&gt;&amp;nbsp;or&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;raj yogi snan.&lt;span style=&quot;font-weight: bolder;&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #faf4eb;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;​&lt;strong&gt;Holi:&lt;/strong&gt;&lt;/p&gt;

&lt;ul data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #faf4eb;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Holi&amp;nbsp;&lt;/span&gt;is a popular&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;ancient Indian festival&lt;/span&gt;, also known as the &amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;Festival of Love&amp;quot;, the &amp;quot;Festival of Colours&amp;quot; and the &amp;quot;Festival of Spring&amp;quot;.&lt;/span&gt;&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;The festival celebrates the eternal and divine love of Radha Krishna.&lt;/li&gt;
	&lt;li&gt;It is&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;celebrated every year&lt;/span&gt;&amp;nbsp;on the day after the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;full moon in the Hindu month of&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Phalgun&amp;nbsp;&lt;/span&gt;which is early March.&lt;/li&gt;
	&lt;li&gt;
	&lt;div aria-level=&quot;3&quot; role=&quot;heading&quot;&gt;Holi Celebrations in the different states of India&lt;/div&gt;

	&lt;div&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Rang Panchami &amp;ndash; Maharashtra&lt;/span&gt;.

		&lt;ul&gt;
			&lt;li&gt;In Maharashtra, Holi is also known as Shigma or Rang Panchami (colour on the fifth)&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;Holla Mohalla- Punjab&lt;/li&gt;
		&lt;li&gt;Shigmo- Goa&lt;/li&gt;
		&lt;li&gt;Royal Holi- Udaipur&lt;/li&gt;
		&lt;li&gt;Kumaoni Holi - Uttarakhand&lt;/li&gt;
		&lt;li&gt;Manjal Kuli- Kerala&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/div&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;कुंभ मेला &lt;/strong&gt;है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;कुंभ मेला &lt;/strong&gt;हिंदू धर्म में एक प्रमुख त्योहार और तीर्थ है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;कुंभ &lt;/strong&gt;का त्योहार लगभग &lt;strong&gt;12 वर्षों के चक्र में चार नदी-तट तीर्थ स्थलों पर&lt;/strong&gt; मनाया जाता है।&lt;/li&gt;
	&lt;li&gt;स्थल हैं
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;प्रयागराज (गंगा-यमुना सरस्वती नदियों का संगम)&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;नासिक (गोदावरी)&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;हरिद्वार (गंगा)&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;उज्जैन (शिप्रा)&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;2013&lt;/strong&gt; में महाकुंभ मेला और &lt;strong&gt;2019&lt;/strong&gt; में प्रयागराज&amp;nbsp;अर्ध कुंभ मेले में लगभग &lt;strong&gt;30 और 50 लाख लोगों&lt;/strong&gt; ने भाग लिया।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अमावस्या पर,&lt;/strong&gt; तीर्थयात्रियों का स्वागत करने के लिए सबसे पसंदीदा दिन है और तेरह साधु अखाड़ों के पहले स्नान करने की प्रतीक्षा करते हैं।&lt;/li&gt;
	&lt;li&gt;इस कार्यक्रम को&lt;strong&gt; शाही स्नान &lt;/strong&gt;या&lt;strong&gt; राजयोगी स्नान &lt;/strong&gt;कहा जाता है&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;होली:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;होली &lt;/strong&gt;एक &lt;strong&gt;लोकप्रिय प्राचीन भारतीय त्योहार&lt;/strong&gt; है, जिसे &amp;quot;&lt;strong&gt;प्यार का त्योहार&amp;quot;, &amp;quot;रंगों का त्योहार&amp;quot; और &amp;quot;वसंत का त्योहार&amp;quot;&lt;/strong&gt; के रूप में भी जाना जाता है।&lt;/li&gt;
	&lt;li&gt;त्योहार राधा कृष्ण के शाश्वत और दिव्य प्रेम का जश्न मनाता है।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;प्रत्येक वर्ष&lt;/strong&gt; &lt;strong&gt;फाल्गुन के हिंदू महीने में पूर्णिमा&lt;/strong&gt; के बाद के दिन&lt;strong&gt; मनाया जाता है &lt;/strong&gt;जो मार्च की शुरुआत में होता है।&lt;/li&gt;
	&lt;li&gt;भारत के विभिन्न राज्यों में होली समारोह
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;रंग पंचमी - महाराष्ट्र&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;महाराष्ट्र में, होली को शिमगा या रंग पंचमी के रूप में भी जाना जाता है।&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;होल्ला मोहल्ला- पंजाब&lt;/li&gt;
		&lt;li&gt;शिमगो - गोवा&lt;/li&gt;
		&lt;li&gt;रॉयल होली - उदयपुर&lt;/li&gt;
		&lt;li&gt;कुमाऊंनी होली - उत्तराखंड&lt;/li&gt;
		&lt;li&gt;मंजल कुली- केरल&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

The correct answer is&amp;nbsp;Shri Sandeep Sangwan
